// Fire when last-minute multicast volume jumps >= 20% above the
// trailing 9-minute baseline.
function handler(input) {
  var dr = (input && typeof input.diff_ratio !== 'undefined' && input.diff_ratio !== null)
    ? Number(input.diff_ratio)
    : 0;
  return { is_alarm: dr >= 0.2 };
}
